package com.hospital.management.controller.prescription;import com.hospital.management.service.*;import com.hospital.management.service.impl.PrescriptionServiceImpl;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;import java.util.Set;@WebServlet("/prescriptions/status")public class PrescriptionStatusServlet extends HttpServlet {private final PrescriptionService service;public PrescriptionStatusServlet(){this(new PrescriptionServiceImpl());}public PrescriptionStatusServlet(PrescriptionService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws IOException{r.sendError(405);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws IOException{Long id=PrescriptionRequest.id(q.getParameter("prescriptionId"));String a=q.getParameter("action");if(id==null||!Set.of("complete","cancel").contains(a)){r.sendError(400);return;}ServiceResult<Void>x=service.updatePrescriptionStatus(id,a,PrescriptionRequest.audit(q),PrescriptionRequest.user(q));r.sendRedirect(q.getContextPath()+"/prescriptions/view?id="+id+"&"+(x.isSuccess()?"message=updated":"error=status"));}}
